```
using System.Globalization;

var res = new Solution().LShapedFlowers(
    4, 4, mod: 4, magic: 1
);

Console.WriteLine("\n" + res);

public class Solution
{
    int m;
    int n;
    int magic;
    int mod;

    static (int, int) upLeft = (-1, -1);
    static (int, int) upRight = (-1, 1);
    static (int, int) downLeft = (1, -1);
    static (int, int) downRight = (1, 1);

    static ((int, int), (int, int))[] directions = new[]{
        (upLeft, upRight), // upper diagonals
        (downLeft, downRight), // down diagonals
        (upLeft, downLeft), // left diagonals
        (upRight, downRight), // right diagonals
    };

    public bool IsFlower(int i, int j)
    {
        return (i + j + magic) % mod % 2 > 0;
    }

    public int LShapedFlowers(int m, int n, int magic, int mod)
    {
        this.m = m;
        this.n = n;
        this.magic = magic;
        this.mod = mod;

        var count = 0;
        var seen = new HashSet<(int, int)>();

        PrintGarden();

        for (var i = 0; i < m; i++)
        {
            for (var j = 0; j < n; j++)
            {
                if (!IsFlower(i, j))
                {
                    continue;
                }

                var counted = new List<(int, int)>();

                // flower, count L's
                foreach (var d in directions)
                {
                    var flowersL = new (int, int)[] {
                        (i, j),
                        (i + d.Item1.Item1, j + d.Item1.Item2),
                        (i + d.Item2.Item1, j + d.Item2.Item2)
                    };

                    // Console.WriteLine($"Checking {flowersL[0]} {flowersL[1]} {flowersL[2]}");

                    // bounds
                    if (flowersL.Any(x => x.Item1 < 0 || x.Item1 > m - 1 || x.Item2 < 0 || x.Item2 > n - 1))
                        continue;

                    // it's missing flowers
                    if (!flowersL.All(x => IsFlower(x.Item1, x.Item2)))
                        continue;

                    // counted already in full
                    if (flowersL.All(x => seen.Contains(x)))
                        continue;

                    foreach (var f in flowersL)
                        counted.Add(f);

                    Console.WriteLine($"Counting {flowersL[0]} {flowersL[1]} {flowersL[2]}");
                    count++;
                }

                foreach (var c in counted)
                    seen.Add(c);
            }
        }

        return count;
    }

    public void PrintGarden()
    {
        for (var i = 0; i < m; i++)
        {
            Console.WriteLine();
            for (var j = 0; j < n; j++)
            {
                if (!IsFlower(i, j))
                {
                    Console.Write(" . ");
                    continue;
                }

                Console.Write(" F ");

            }
        }
        Console.WriteLine();
    }
}
